import{_ as e,o as a,c as t,ak as _}from"./chunks/framework.BwREiRwV.js";const m=JSON.parse('{"title":"第十四章 山门警钟","description":"","frontmatter":{},"headers":[],"relativePath":"永恒道途/正文/第一卷-山门有路/第十四章-山门警钟.md","filePath":"永恒道途/正文/第一卷-山门有路/第十四章-山门警钟.md"}'),r={name:"永恒道途/正文/第一卷-山门有路/第十四章-山门警钟.md"};function o(n,p,s,c,i,d){return a(),t("div",null,[...p[0]||(p[0]=[_('<h1 id="第十四章-山门警钟" tabindex="-1">第十四章 山门警钟 <a class="header-anchor" href="#第十四章-山门警钟" aria-label="Permalink to &quot;第十四章 山门警钟&quot;">​</a></h1><p>赤色急讯符越过山脊后不到半刻钟，青云宗山门警钟响了。</p><p>钟声从极远处传来，先是一记沉响，隔三息又响两记。枣木村南坡祠堂的瓦片随余音轻颤，屋檐积灰落下一层。村民不知道三声是什么意思，外巡队的人却同时停下手中动作。</p><p>一声，召当值。</p><p>两声，封外门。</p><p>三声，山外有敌。</p><p>巡队首领姓章，炼气九层。他把陈玄交来的蜡纸包、阵粉与地图放进封灵匣，先验急讯符是否成功穿过遮气范围，再向两名弟子下令。</p><p>“一人守村，一人去北坡接山门援队。没有我的口令，任何人不得往黑风涧走。”</p><p>安排完，他才转向陈玄：“先入祠堂治伤。”</p><p>“血引阵位置还需重画。”</p><p>“你能坐着画？”</p><p>“能。”</p><p>“那便坐着。”章首领没有说伤者不许管，也没有让他站在风里证明清醒，“医师替你拆布时，你口述，我画。”</p><p>祠堂临时摆了三张木床。</p><p>陈玄趴到最里一张，外巡医师剪开背后布带。十日里反复结痂、渗血的伤口重新露出，边缘已有两处红肿。十五年回脉草清掉了血煞，却不等于河水带进的污物也一并消失。</p><p>医师先嗅伤口，再以银片刮下一点薄痂。</p><p>“血煞已排，腰侧有腐热。右肋骨裂，脚腕软伤。谁给你正的骨？”</p><p>“没有正，木片固定。”</p><p>“算你没乱按。”</p><p>温药冲过伤口，疼痛沿脊背一下绷紧。陈玄把折好的布咬在齿间，仍按章首领的问题逐一说出：何处发现遮气阵粉，何处细索被换，裂齿獠熊从哪一面出现，东南假节点与另外六处阵光分别在什么方向。</p><p>章首领不照着他的原图抄。</p><p>每画一个点，都会换一种问法再核一次。</p><p>“你落水前，月在哪边？”</p><p>“右前，约过子时。”</p><p>“北坡高于阵心多少？”</p><p>“看不全，至少三丈。”</p><p>“郑衡向哪边走？”</p><p>“西。第一步落在三号阵钉后，之后被烟遮住。”</p><p>“陆炳呢？”</p><p>“北坡。斩断脚线时还能持刀。”</p><p>“亲眼看见二人倒下没有？”</p><p>“没有。”</p><p>章首领在两人名字后都写“失散”，没有写“亡”。</p><p>陈玄交出半块郑字牌：“这是落坡前捡到的。断口是新痕。”</p><p>“身份牌有护主细绳，除非被阵线扯断，不易掉。”章首领将断牌另装一袋，“可以缩小搜寻范围，不能当死讯。”</p><p>这与陈玄在外巡点说的一样。</p><p>他绷了十日的那口气稍微松了一点。</p><p>医师趁他呼吸放缓，将伤口中一小片腐肉剪去。剪刀合拢的声音很轻，陈玄额头却立刻渗出冷汗。腐热处敷上药泥后，医师没有给他服整枚疗伤丹，只将一枚清创丹分成四份，先喂一份观察。</p><p>“你自行用过什么药？”</p><p>“十五年左右回脉草，分五次，内服三片，外敷两次。黄精，止血散。”</p><p>“哪来的十五年药？”章首领抬眼。</p><p>这个问题早在陈玄决定带回两片叶时便想过。</p><p>“家传《山药札记》记有一处暗河药点。逃亡时在洞中寻到，叶脉银白，约十五年。根茎仍留在原处。”</p><p>他说的并非全真。</p><p>山洞、药性和根茎都在，唯独十五年不是自然长成。若宗门以后按路线去找，能看见活药，也能核对洞土。掌天瓶仍被藏在唯一不能被核对的一段里。</p><p>章首领没有立刻信，也没有此时追问：“位置列入任务复核。回宗后刑律峰会再问。”</p><p>“是。”</p><p>医师看过两片蜡封药叶，确认药性无邪，才把它们重新还给陈玄。</p><p>伤要治，口供也要查。</p><p>两件事可以同时做，不必因他带回证据便相信全部，也不必因一句话待核便拖延救治。</p><p>又过一刻钟，山门援队抵达北坡。</p><p>不是一队。</p><p>三道青色警旗从林上依次显出。第一队由刑律峰筑基执事带领，直去黑风涧；第二队沿西北搜索可能据点；第三队留在枣木村外，布下隔绝血松脂的净气阵，并护送附近三村向南暂迁。</p><p>一名传讯弟子进祠堂取复画地图。</p><p>陈玄撑着坐起：“黑风涧血阵以獠熊和旧血供能。若熊仍活，先断颈下驱兽刺，不要直接以火攻阵。血松脂遇火会让它更狂。”</p><p>传讯弟子看向章首领。</p><p>“照录。”章首领道，“另加一句：上一队幸存者邹平反复说不要点香。救援队不得使用诱妖香。”</p><p>地图被封进竹筒带走。</p><p>陈玄不能同行。</p><p>他甚至不能走到祠堂门口。清创药效上来后，背部时冷时热，右脚也肿得穿不回鞋。能做的只剩躺着听外面每一次符鸟落地。</p><p>第一只符鸟在午后回来。</p><p>黑风涧血阵仍在，阵心已空。裂齿獠熊死在东南老树旁，颈下黑刺拔去五枚，腹部有血线反复抽取的孔洞。阵中找到陆炳的厚背刀与郑衡两枚烧毁阵钉，没有尸体。</p><p>第二只符鸟晚半个时辰。</p><p>北坡暗河上游发现血迹两处，一处向西，一处向北。向北的痕迹在四里外断于石洞，洞口有人用厚背刀刻过三道短痕。</p><p>三道。</p><p>是任务小队后院试阵时定的求援记号。</p><p>陆炳至少走到过那里。</p><p>陈玄闭了一下眼。</p><p>不是庆幸人一定活着，只是原本全黑的一处有了方向。</p><p>日落前，第三只符鸟带回一句话：西线寻到伤员一名，郑衡，尚有气息。</p><p>祠堂外巡弟子低低欢呼了一声，很快被章首领制止。郑衡胸骨裂伤、灵力耗尽，在冷山里藏了十日，“尚有气息”离“活下来”仍隔着很长一段药路。</p><p>陈玄问：“陆炳呢？”</p><p>“北线还在搜。”</p><p>天黑后，祠堂点起七盏油灯。</p><p>陈玄没有睡。药效让身体沉重，耳朵却一直听着门外。他想起陆炳在档房说，接朱榜是因为内门预选还差二十四贡献；想起他试网时将打滑的那一步走了三遍；又想起血阵中那句消息钱要有人收。</p><p>这些事与“炼气六层刀修”无关。</p><p>是一个人留在世上的细小形状。</p><p>亥时，北线救援回讯。</p><p>陆炳被找到时还活着。</p><p>他藏在一处废弃獾洞里，右肩撕裂，左腿血线入骨，神志清醒却无法行走。发现救援队后，他第一句话不是求药，而是说洞外三十步埋着一张未触发的火符，让人别踩。</p><p>章首领念完讯文，祠堂里没人说话。</p><p>陈玄缓缓松开一直握着的床沿。</p><p>十日。</p><p>没有谁靠一句兄弟情便轻易撑过。陆炳随身的两枚回灵丹全用完，以刀割腐肉，靠山鼠存下的干果和积水活着；郑衡则把自己封进一个不完整敛气阵，阵钉耗尽后拆下腰牌里的灵木续阵，所以陈玄捡到的只有半块断牌。</p><p>他们各自用了会的东西。</p><p>也等到了陈玄带回的那张地图。</p><p>两名伤员当夜被送回青云宗。外巡医师不让陈玄同行，理由很简单：他的伤经不起飞舟颠簸，明晨走地路更稳。</p><p>陈玄没有争。</p><p>救援不是比赛谁先回山门。多等一夜能少裂一次伤口，便该等。</p><p>西北搜索队的消息直到翌日清晨才到。</p><p>山坳确有一座废弃石寨。</p><p>寨中人已于两日前撤离，柴火尚新，地窖留有血松脂、驱兽钉、青云宗制式药瓶和九块被刮去姓名的身份牌。墙上画着未完成的血引图，红石谷、黑风涧及另外两处山口都被圈过。</p><p>刑律峰没有因为人去楼空便把结果写成“查无所获”。</p><p>物证被封，山口被控，两名去红石谷探路的血魔宗弟子也在途中被截住一人。被俘者腰牌内侧刻着“血七”二字，口供只提到一个称号。</p><p>血魔子。</p><p>他不是此次在场的伏击者，而是黑风山数处引兽阵的上级布置者。血魔宗需要外门修士与妖兽搏杀后的血气养阵，便把受伤妖兽驱向凡人村落，等宗门挂出任务，再以一支又一支小队填进去。</p><p>这不是两名邪修临时起意。</p><p>是一条把村民报险、宗门发榜和外门弟子求贡献都算在内的猎路。</p><p>陈玄听完供词摘要，最先想到任务殿那张双圈朱榜。</p><p>标出未知风险仍然不够。</p><p>如果同类伤亡、同类血迹与同一区域的任务记录彼此分开存放，后来者每次都要从十九句疯话里重新猜一遍。朱砂能提醒人危险，却不能自己告诉人危险从哪里来。</p><p>当日午后，外巡队以地车送陈玄回宗。</p><p>山门外的三层阵门全部关闭，来往弟子逐一验牌。任务殿暂停黑风山所有猎妖任务，刑律峰与外巡堂共同复核近半年失联记录。药堂则把血煞伤单独列册，要求以后每支朱榜队伍至少携带一株回脉草苗与净气符。</p><p>这些改变不全因陈玄一人。</p><p>前队邹平带回断腿与疯话，郑衡认出血松脂，陆炳在阵里牵住獠熊，三村村民说清驱兽时间，外巡队找到石寨。陈玄只是把散落的东西带过暗河，放到一张桌上。</p><p>可若没有人带回来，它们仍会彼此分散。</p><p>地车进入山门时，警钟又响了一次。</p><p>这一次不是三声急促示警，而是十二声慢钟。</p><p>每一声，对应近半年确认死在黑风山血阵中的一名青云弟子。身份牌有九块，另三人只从任务记录与家属留档中确认，再没有遗物。</p><p>山道上的人陆续停步。</p><p>有人摘下斗笠，有人放下药筐，也有人不知道名字，只随着钟声沉默。十二声之间隔得很长，长到足以让一个人的名字被念完。</p><p>陈玄躺在地车上，看不见主峰，只能看见车篷边一线天光。</p><p>第十二声落下后，药堂门前出现两道身影。</p><p>韩执事站在石阶下，脸色比平日更沉。鲁老头在他身后，烟杆没有点火，手中还攥着半块没吃完的灵谷饼。</p><p>地车停稳，鲁老头先看陈玄的脸，再看胸前与背后布带。</p><p>“还知道回来？”</p><p>“回来晚了。”</p><p>“回来便不算晚。”老人说完，像嫌这句话太软，立刻又骂，“下次再把自己泡河里十日，药园不给你留铺。”</p><p>韩执事没有问他杀了几人，也没有在门口追问口供。</p><p>“陆炳和郑衡已进内伤堂。一个要保腿，一个要保心脉，都还没过险期。”他说，“你先治自己的。刑律峰要问话，等医师说能问再来。”</p><p>话音刚落，内伤堂方向有人快步过来。</p><p>苏婉换了丹峰窄袖药袍，袖口束在腕上，手里拿着两份新抄伤单。她没有因陈玄从黑风山回来便先问惊险经过，走到地车旁的第一句话是：“回脉草用了多少？”</p><p>“十五年上下。前四日共用五片，内服三片，外敷两次。第四日排出黑血七滴，此后停药。”</p><p>“最后一次用药后，有没有心悸、耳鸣或手指发冷？”</p><p>“耳鸣半个时辰，手指没有发冷。”</p><p>苏婉在伤单上记下，又问黄精、止血散和每日饮水。陈玄逐项答完，她才让医师翻看后背敷料。</p><p>“血煞已清，不代表回脉草没有余性。”她道，“今夜不许服养气散，也不运行完整周天。清创药与回脉草都走经脉，两种药至少隔三个时辰。”</p><p>“内伤堂那边如何？”陈玄问。</p><p>“郑衡的雷符震伤心脉，先保气血；陆炳左腿血线入骨，腐处已清，能不能保住要看今晚。”苏婉没有用一句“都会没事”敷衍他，“你带回的两片叶会分别验药，不直接同方。三个人的伤因相近，伤势不同，不能照着你的剂量抄。”</p><p>她将其中一份伤单交给韩执事：“这是陆炳清醒后补的阵中记录。他说陈玄第三息已出阵，没有临阵弃队。刑律峰问话时，把这一份一并归档。”</p><p>陈玄看向纸页。</p><p>那不是一封替他辩白的信，只是陆炳把看见的顺序写清了。可在三人失散、只有陈玄先回来的情形下，这个顺序能挡住许多日后无从核对的猜测。</p><p>“等他醒了，我去谢。”</p><p>“先等你自己能走。”苏婉把伤单收回匣中，“药堂不缺一个会说谢的人，缺肯按医嘱躺够时辰的伤者。”</p><p>说完，她便转去接下一辆地车。后面还有两名搜阵时被血线割伤的巡山弟子，并没有因为陈玄是带回证据的人便让他占去更多时间。</p><p>陈玄点头。</p><p>被抬过药堂门槛前，他把一直贴身收着的两片回脉草叶交给医师，说明药龄、已用剂量与自身反应。</p><p>医师没有因是十五年药便全部给他煎下。</p><p>只取半片，另半片送去内伤堂验配。</p><p>同一种药，落到不同伤者身上，也该重新称量。</p><p>陈玄趴在药床上，听见外面有人抄写新的血煞伤处置条目。警钟余音还在山谷间一层层回荡，已经比最初轻了许多。</p><p>他没有胜后的畅快。</p><p>血魔宗据点已经撤走，布阵的人大半仍活着，血魔子只是口供里的一个称号。十二声钟也不能把死者换回来。</p><p>但从今日起，任务殿再有人看见黑风山朱榜，至少不会只看见两个红圈。</p><p>他们会看见那张网怎样铺成。</p><p>也会知道，退回来把变化说清，不是怯战。</p><p>有时是让下一支队伍活下去的第一步。</p><p>（第十四章完）</p>',148)])])}const f=e(r,[["render",o]]);export{m as __pageData,f as default};
